import '../lib/assembler.dart';
import '../lib/chunk_ledger.dart';
import '../lib/content_range.dart';

void ensure(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final ledger = ChunkLedger(24);
  final accepted = [
    'bytes 0-7/24',
    'bytes 8-15/24',
    'bytes 16-23/24',
  ].map(ContentRange.parse).every(ledger.accept);
  final bytes = assembleChunks({
    0: List.generate(8, (index) => index),
    8: List.generate(8, (index) => index + 8),
    16: List.generate(8, (index) => index + 16),
  }, 24);

  ensure(accepted && ledger.isComplete, 'sealed upload never became complete');
  ensure(bytes[8] == 8 && bytes[16] == 16, 'sealed upload order was corrupted');
}
